import { getValidColor } from './getValidColor.js';
import { ColoredRange } from '../types/colored-range.js';

const isOverlappingRange = (a: ColoredRange, b: ColoredRange) =>
  b.from >= a.from && b.from < a.to;

const isContinuousRange = (a: ColoredRange, b: ColoredRange) => a.to === b.from;

/**
 * Normalizes the threshold ranges
 *
 * Add ranges if a gap is detected
 * Assigns default color to ranges without color
 * Skips overlapping ranges
 *
 * @param ranges - a sorted array of threshold ranges
 * @param defaultColor - default color for ranges
 */
export const normalizeColoredRanges = (
  ranges: ColoredRange[],
  defaultColor: string,
): Required<ColoredRange>[] => {
  let [a] = ranges;
  a = normalizeColoredRange(a);
  const normalizedRange = [a];
  for (let i = 1; i < ranges.length; i++) {
    const b = normalizeColoredRange(ranges[i]);
    if (!isOverlappingRange(a, b)) {
      if (isContinuousRange(a, b)) {
        normalizedRange.push(b);
      } else {
        normalizedRange.push({
          from: a.to,
          to: b.from,
          color: defaultColor,
        });
        normalizedRange.push(b);
      }
      a = b;
    }
  }

  return normalizedRange as Required<ColoredRange>[];
};

/**
 * Adds default color to range if missing
 *
 * @param range -
 * @param defaultColor - default color for ranges
 */
export const normalizeColoredRange = (
  range: ColoredRange,
): Required<ColoredRange> => {
  range.color = getValidColor(range.color);
  return range as Required<ColoredRange>;
};
